3	/* ── Design tokens ───────────────────────────────────────────────────────── */
4	:host {
5	  @include styles.page-component-layout;
6	  display: flex;
7	  flex-direction: column;
8	  height: 100%;
9	  overflow: hidden;
10	  font-family: 'Hanken Grotesk', system-ui, sans-serif;
11	
12	  --ink:       #1c1b22;
13	  --ink-2:     #46454f;
14	  --ink-3:     #76747f;
15	  --ink-4:     #a8a6af;
16	  --line:      #e7e3dd;
17	  --line-2:    #f0ece6;
18	  --paper:     #ffffff;
19	  --bg:        #f5f3ef;
20	  --chip:      #f1eee9;
21	  --brand:     #3f3d86;
22	  --brand-700: #302e63;
23	  --brand-50:  #ecebf6;
24	  --accent:    #c2662f;
25	  --accent-700:#9a4f23;
26	  --accent-50: #f7ece2;
27	}
28	
29	/* ── Command bar ─────────────────────────────────────────────────────────── */
30	.command-bar {
31	  display: flex;
32	  align-items: center;
33	  flex-wrap: wrap;
34	  gap: 8px;
35	  padding: 10px 20px;
36	  background: var(--paper);
37	  border-bottom: 1px solid var(--line);
38	  flex-shrink: 0;
39	  min-height: 56px;
40	  box-sizing: border-box;
41	}
42	
43	.cmd-brand {
44	  display: flex;
45	  align-items: center;
46	  gap: 8px;
47	  flex-shrink: 0;
48	}
49	
50	.brand-tile {
51	  width: 28px;
