64	  }
65	}
66	
67	.brand-title {
68	  font-size: 15px;
69	  font-weight: 800;
70	  letter-spacing: -0.02em;
71	  color: var(--ink);
72	  white-space: nowrap;
73	}
74	
75	.cmd-vr {
76	  width: 1px;
77	  height: 24px;
78	  background: var(--line);
79	  flex-shrink: 0;
80	  margin: 0 2px;
81	}
82	
83	.cmd-create {
84	  background: var(--accent) !important;
85	  color: #fff !important;
86	  border-radius: 9px !important;
87	  height: 36px;
88	  padding: 0 14px;
89	  font-size: 13.5px;
90	  font-weight: 600;
91	  flex-shrink: 0;
92	  box-shadow: none !important;
93	
94	  mat-icon {
95	    font-size: 18px;
96	    width: 18px;
97	    height: 18px;
98	    margin-right: 4px;
99	  }
100	
101	  &:hover { background: var(--accent-700) !important; }
102	}
103	
104	.cmd-search {
105	  flex: 1 1 180px;
106	  min-width: 150px;
107	  max-width: 360px;
108	}
109	
110	/* Field-button (Display, Filters, etc.) */
111	.cmd-field-btn {
112	  display: inline-flex;
113	  align-items: center;
114	  gap: 5px;
115	  height: 36px;
116	  padding: 0 12px;
117	  border-radius: 9px;
118	  border: 1px solid var(--line);
119	  background: var(--paper);
120	  color: var(--ink-2);
121	  font-size: 13px;
122	  font-weight: 500;
123	  cursor: pointer;
124	  white-space: nowrap;
125	  transition: background 0.1s, border-color 0.1s, color 0.1s;
126	
127	  &:hover { border-color: var(--ink-3); }
128	
129	  &.active {
130	    background: var(--brand-50);
131	    border-color: var(--brand);
132	    color: var(--brand-700);
133	
134	    .chev { transform: rotate(180deg); }
135	  }
136	
137	  .btn-icon { font-size: 16px; width: 16px; height: 16px; }
138	  .chev     { font-size: 16px; width: 16px; height: 16px; transition: transform 0.15s; }
139	}
140	
141	/* Display menu wrapper */
142	.cmd-display-wrap {
143	  position: relative;
144	  flex-shrink: 0;
145	}
146	
147	/* Display popover */
148	.display-popover {
149	  position: absolute;
150	  top: calc(100% + 6px);
151	  left: 0;
152	  z-index: 200;
153	  background: var(--paper);
154	  border: 1px solid var(--line);
155	  border-radius: 13px;
156	  box-shadow: 0 12px 32px rgba(28,27,34,.16), 0 2px 6px rgba(28,27,34,.08);
157	  padding: 8px 0;
158	  min-width: 260px;
159	  animation: lib-pop .12s ease;
160	}
161	
162	.pop-section {
163	  padding: 8px 14px;
164	}
165	
166	.pop-label {
167	  font-size: 10px;
168	  font-weight: 700;
169	  text-transform: uppercase;
170	  letter-spacing: 0.07em;
171	  color: var(--ink-4);
172	  margin-bottom: 7px;
173	}
174	
175	.pop-divider {
176	  border-top: 1px solid var(--line-2);
177	  margin: 4px 0;
178	}
179	
180	/* Segmented controls */
181	.seg-group {
182	  display: flex;
183	  background: var(--chip);
184	  border-radius: 9px;
185	  padding: 3px;
186	  gap: 2px;
187	}
188	
189	.seg-btn {
190	  flex: 1;
191	  display: inline-flex;
192	  align-items: center;
193	  justify-content: center;
194	  gap: 5px;
195	  height: 30px;
196	  padding: 0 10px;
197	  border: none;
198	  border-radius: 7px;
199	  background: transparent;
200	  color: var(--ink-3);
201	  font-size: 12.5px;
202	  font-weight: 500;
203	  cursor: pointer;
204	  white-space: nowrap;
205	  transition: background 0.1s, color 0.1s, box-shadow 0.1s;
206	
207	  mat-icon { font-size: 15px; width: 15px; height: 15px; }
208	
209	  &.seg-active {
210	    background: var(--paper);
211	    color: var(--ink);
212	    font-weight: 600;
213	    box-shadow: 0 1px 2px rgba(28,27,34,.12);
214	  }
215	
216	  &:hover:not(.seg-active) { color: var(--ink-2); }
217	}
218	
219	/* Columns checklist */
220	.col-checklist {
221	  display: flex;
222	  flex-direction: column;
223	  gap: 3px;
224	}
225	
226	.col-check-item {
227	  display: flex;
228	  align-items: center;
229	  gap: 8px;
230	  font-size: 13px;
231	  color: var(--ink-2);
232	  cursor: pointer;
233	  padding: 3px 2px;
234	  border-radius: 5px;
235	
236	  input[type="checkbox"] {
237	    width: 15px;
238	    height: 15px;
239	    accent-color: var(--brand);
240	    cursor: pointer;
241	    flex-shrink: 0;
242	  }
243	
244	  &:hover { background: var(--chip); }
245	}
246	
247	/* Spacer */
248	.cmd-spacer { flex: 1 1 auto; }
249	
250	/* Icon buttons */
251	.cmd-icon-btn {
252	  width: 36px !important;
253	  height: 36px !important;
254	  border-radius: 9px !important;
255	  border: 1px solid var(--line) !important;
256	  color: var(--ink-2) !important;
257	
258	  mat-icon { font-size: 19px; }
259	
260	  &:hover { border-color: var(--ink-3) !important; }
261	}
262	
263	/* Mat-select fields in command bar */
264	.cmd-field {
265	  height: 36px;
266	  flex-shrink: 0;
267	
268	  ::ng-deep .mat-mdc-text-field-wrapper { background: var(--paper) !important; }
269	  ::ng-deep .mat-mdc-form-field-flex { height: 36px; }
270	  ::ng-deep .mat-mdc-form-field-infix { padding: 0 !important; min-height: 36px !important; display: flex; align-items: center; }
271	}
272	
273	.division-field { width: 140px; }
274	.views-field    { width: 170px; }
275	
276	/* ── View dropdown internals ─────────────────────────────────────────────── */
277	.view-dropdown-actions {
278	  padding: 8px;
279	  border-top: 1px solid var(--line-2);
280	  display: flex;
281	  flex-direction: column;
282	  gap: 8px;
283	}
284	
285	.view-btn-group {
286	  display: flex;
287	  justify-content: space-between;
288	  flex-wrap: wrap;
289	  gap: 4px;
290	}
291	
292	.new-view-input {
293	  display: flex;
294	  gap: 8px;
295	  align-items: center;
296	
297	  .view-input {
298	    border: 1px solid var(--line);
299	    padding: 6px 8px;
300	    border-radius: 7px;
301	    width: 100%;
302	    font-size: 13px;
303	    color: var(--ink);
304	    background: var(--bg);
305	    outline: none;
306	
307	    &:focus { border-color: var(--brand); }
308	  }
309	}
310	
311	/* ── Content area ────────────────────────────────────────────────────────── */
312	.lib-content {
313	  flex: 1;
314	  overflow: hidden;
315	  display: flex;
316	  flex-direction: column;
317	}
318	
319	.gallery-wrap {
320	  flex: 1;
321	  overflow-y: auto;
322	  background: var(--bg);
323	}
324	
325	.table-region {
326	  flex: 1;
327	  display: flex;
328	  overflow: hidden;
329	
330	  &.split-mode {
331	    flex-direction: row;
332	  }
333	}
334	
335	.grid-region {
336	  flex: 1;
337	  position: relative;
338	  overflow: hidden;
339	}
340	
341	.grid-fill {
342	  position: absolute;
343	  inset: 0;
344	}
345	
346	/* ── Split rail ──────────────────────────────────────────────────────────── */
347	.split-rail-wrap {
348	  width: 372px;
349	  flex-shrink: 0;
350	  overflow: hidden;
351	  display: flex;
352	  flex-direction: column;
353	}
354	
355	/* ── Filmstrip hover preview ─────────────────────────────────────────────── */
356	.row-preview {
357	  position: absolute;
358	  right: 12px;
359	  width: 234px;
360	  background: var(--paper);
361	  border: 1px solid var(--line);
362	  border-radius: 13px;
363	  box-shadow: 0 18px 40px rgba(28,27,34,.20), 0 3px 10px rgba(28,27,34,.10);
364	  pointer-events: none;
365	  z-index: 100;
366	  animation: lib-pop .12s ease;
367	  overflow: hidden;
368	}
369	
370	.rp-thumb {
371	  position: relative;
372	  height: 130px;
373	  background: var(--bg);
374	}
375	
376	.rp-img {
377	  width: 100%;
378	  height: 100%;
379	  object-fit: cover;
380	  display: block;
381	}
382	
383	.rp-tile {
384	  width: 100%;
385	  height: 100%;
386	  display: flex;
387	  align-items: center;
388	  justify-content: center;
389	
390	  mat-icon { font-size: 36px; width: 36px; height: 36px; color: var(--ink-3); opacity: .4; }
391	}
392	
393	.rp-code {
394	  position: absolute;
395	  bottom: 6px;
396	  left: 6px;
397	  font-family: 'IBM Plex Mono', ui-monospace, monospace;
398	  font-size: 9px;
399	  font-weight: 600;
400	  background: rgba(28,27,34,.62);
401	  color: #fff;
402	  padding: 1px 5px;
403	  border-radius: 3px;
404	}
405	
406	.rp-body {
407	  padding: 10px 12px 12px;
408	}
409	
410	.rp-name {
411	  font-size: 13px;
412	  font-weight: 600;
413	  color: var(--ink);
414	  line-height: 1.35;
415	  margin-bottom: 3px;
416	  overflow: hidden;
417	  display: -webkit-box;
418	  -webkit-line-clamp: 2;
419	  -webkit-box-orient: vertical;
420	}
421	
422	.rp-meta {
423	  font-family: 'IBM Plex Mono', ui-monospace, monospace;
424	  font-size: 11px;
425	  color: var(--ink-3);
426	  margin-bottom: 8px;
427	}
428	
429	.rp-mini {
430	  display: grid;
431	  grid-template-columns: 1fr 1fr;
432	  gap: 6px 8px;
433	}
434	
435	.rp-field {
436	  display: flex;
437	  flex-direction: column;
438	  gap: 1px;
439	}
440	
441	.rp-fl {
442	  font-size: 9.5px;
443	  font-weight: 700;
444	  text-transform: uppercase;
445	  letter-spacing: .06em;
446	  color: var(--ink-4);
447	}
448	
449	.rp-field > span:last-child {
450	  font-size: 12px;
451	  color: var(--ink-2);
452	}
453	
454	.mono {
455	  font-family: 'IBM Plex Mono', ui-monospace, monospace;
456	}
457	
458	/* ── AG-Grid theme overrides ─────────────────────────────────────────────── */
459	::ng-deep {
460	  /* Row styling */
461	  .ag-theme-alpine .ag-row {
462	    border-bottom: 1px solid var(--line-2, #f0ece6) !important;
463	    background: var(--paper, #fff) !important;
464	    color: var(--ink, #1c1b22);
465	    font-family: 'Hanken Grotesk', system-ui, sans-serif;
466	    font-size: 13px;
467	    transition: background 0.08s;
468	  }
469	
470	  .ag-theme-alpine .ag-row:hover {
471	    background: var(--chip, #f1eee9) !important;
472	  }
473	
474	  .ag-theme-alpine .ag-row-selected {
475	    background: var(--brand-50, #ecebf6) !important;
476	  }
477	
478	  .ag-theme-alpine .ag-row-selected::before {
479	    content: '';
480	    position: absolute;
481	    left: 0;
482	    top: 0;
483	    bottom: 0;
484	    width: 3px;
485	    background: var(--brand, #3f3d86);
486	    z-index: 1;
487	  }
488	
489	  /* Header */
490	  .ag-theme-alpine .ag-header {
491	    background: var(--bg, #f5f3ef) !important;
492	    border-bottom: 1px solid var(--line, #e7e3dd) !important;
493	  }
494	
495	  .ag-theme-alpine .ag-header-cell-label {
496	    font-size: 11px;
497	    font-weight: 700;
498	    text-transform: uppercase;
499	    letter-spacing: .05em;
500	    color: var(--ink-3, #76747f);
501	  }
502	
503	  .ag-theme-alpine .ag-header-cell-sorted-asc .ag-header-cell-label,
504	  .ag-theme-alpine .ag-header-cell-sorted-desc .ag-header-cell-label {
505	    color: var(--brand-700, #302e63);
506	  }
507	
508	  /* Cell borders */
509	  .ag-theme-alpine .ag-cell {
510	    border-right: 1px solid var(--line-2, #f0ece6) !important;
511	    font-family: 'Hanken Grotesk', system-ui, sans-serif;
512	  }
513	
514	  .ag-theme-alpine .ag-cell-focus {
515	    border: 1.5px solid var(--brand, #3f3d86) !important;
516	  }
517	
518	  /* Checkbox */
519	  .ag-theme-alpine .ag-checkbox-input-wrapper {
520	    border-radius: 5px !important;
521	    border-color: var(--line, #e7e3dd) !important;
522	  }
523	
524	  .ag-theme-alpine .ag-checkbox-input-wrapper.ag-checked {
525	    background: var(--brand, #3f3d86) !important;
526	    border-color: var(--brand, #3f3d86) !important;
527	  }
528	
529	  /* Pagination panel */
530	  .ag-paging-panel {
531	    background: var(--paper, #fff) !important;
532	    border-top: 1px solid var(--line, #e7e3dd) !important;
533	    font-family: 'IBM Plex Mono', ui-monospace, monospace;
534	    font-size: 12px;
535	    color: var(--ink-2, #46454f);
536	    justify-content: center !important;
537	  }
538	
539	  /* Filter toolpanel */
540	  .ag-filter-toolpanel-group-level-0-header,
541	  .ag-filter-toolpanel-group-level-0-header .ag-group-title,
542	  .ag-filter-toolpanel-group-level-0-header span,
543	  .ag-filter-toolpanel-group-title {
544	    color: var(--brand, #3f3d86) !important;
545	  }
546	
547	  /* Pic cell alignment */
548	  .ag-cell[col-id="pic"] {
549	    display: flex !important;
550	    align-items: center !important;
551	    justify-content: center !important;
552	    padding: 4px !important;
553	  }
554	
555	  /* Status / property cells — remove default padding so pills align flush */
556	  .ag-cell[col-id="status"],
557	  .ag-cell[col-id="property"] {
558	    display: flex !important;
559	    align-items: center !important;
560	  }
561	}
562	
563	/* Compact density: tighten font slightly */
564	.density-compact {
565	  ::ng-deep .ag-theme-alpine .ag-row {
566	    font-size: 12px;
567	  }
568	
569	  ::ng-deep .ag-theme-alpine .ag-cell[col-id="pic"] app-item-thumbnail .thumb-frame {
570	    width: 34px;
571	    height: 34px;
572	  }
573	}
574	
575	/* ── Animation ───────────────────────────────────────────────────────────── */
576	@keyframes lib-pop {
577	  from { opacity: 0; transform: translateY(-3px); }
578	  to   { opacity: 1; transform: translateY(0); }
579	}
