:host {
  background: var(--toolbar-background);
  box-sizing: border-box;
  color: var(--toolbar-color);
  display: block;
  white-space: nowrap;
  width: 100%;
  z-index: var(--toolbar-z-index);
  /* Allow PrimeNG menubar submenus to extend outside without clipping */
  overflow: visible;
}

.toolbar {
  height: var(--toolbar-height);
}

/* Align nav block like left (Designflow) and right (icons): same padding rhythm */
.vex-toolbar-nav {
  flex: 1 1 auto;
  min-width: 0; /* allow shrinking below content size so right-side icons stay visible */
  /* PrimeNG menubar submenus are absolutely positioned below the nav row */
  overflow: visible;
  position: relative;
  display: flex;
  align-items: center;
  padding-left: var(--padding-gutter, 1rem);
  padding-right: var(--padding-gutter, 1rem);
  min-height: var(--toolbar-height);
  margin-bottom: 35px;
  border-radius: 6px;
  transition: background-color 0.2s ease;
}

.mat-icon,
iconify-icon,
ic-icon {
  color: var(--toolbar-icon-color);
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  transform-origin: center;
  cursor: pointer;
}

.mat-icon:hover,
iconify-icon:hover,
ic-icon:hover {
  color: var(--accent-color, #3f51b5);
}

button:has(iconify-icon[icon*="icMenu"]) iconify-icon:hover {
  transform: scale(1.1);
}

/* Click animations */
button:active .mat-icon,
button:active iconify-icon,
button:active ic-icon {
  transform: scale(0.95);
  transition: transform 0.1s ease;
}

/* Arrow dropdown animation */
ic-icon[icon*="icArrowDropDown"] {
  transition: transform 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

button[aria-expanded="true"] ic-icon[icon*="icArrowDropDown"] {
  transform: rotate(180deg);
}

/* Menu item animations */
.mat-menu-item iconify-icon {
  transition: transform 0.2s ease;
}

.mat-menu-item:hover iconify-icon {
  transform: translateX(4px);
}

/* Bounce animation for menu items */
.mat-menu-item {
  transition: all 0.3s cubic-bezier(0.68, -0.55, 0.265, 1.55);
}

.mat-menu-item:hover {
  transform: translateY(-2px);
  background-color: rgba(63, 81, 181, 0.1);
}

/* Logo hover effect */
a:hover img {
  transform: scale(1.05);
  transition: transform 0.3s ease;
}

a:hover h1 {
  color: var(--accent-color, #3f51b5);
  transition: color 0.3s ease;
}

a {
  color: var(--toolbar-color);
  text-decoration: none;
}

/* Ensure consistent icon alignment inside the toolbar */
:host ::ng-deep .toolbar .flex.items-center > div {
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 0 4px; /* same horizontal padding for each block */
}

/* Normalize button padding and icon size */
:host ::ng-deep button[mat-icon-button] {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 40px;
  height: 40px;
  padding: 0;
}

/* Make sure all icons are visually centered */
:host ::ng-deep iconify-icon,
:host ::ng-deep .mat-icon {
  display: flex;
  align-items: center;
  justify-content: center;
  vertical-align: middle;
  color: var(--toolbar-icon-color);
  transition: color 0.2s ease;
}

/* put in styles.scss (global) */
[role="tooltip"] {
  /* initial (hidden) state */
  opacity: 0;
  transform: translateY(8px) scale(0.96);
  transform-origin: center bottom;
