@use "../../../styles" as styles;

:host {
  @include styles.page-component-layout;
}

::ng-deep .price-requested-cell {
  background-color: #ffe082 !important;
}

/* --- Main Toolbar Layout --- */
.rfq-toolbar {
  display: flex;
  align-items: center;
  padding: 0px 16px;
  background-color: #fff;
  border-bottom: 1px solid #e0e0e0;
  height: auto;
  min-height: 55px; /* Sufficient height for inputs */
  box-sizing: border-box;
  flex-wrap: wrap; /* Allow wrapping on small screens */
  gap: 12px;
}

.toolbar-left, .toolbar-right {
  display: flex;
  align-items: center;
  gap: 12px;
}

.toolbar-spacer {
  flex: 1 1 auto;
}

.admin-group, .filter-group, .view-group, .utility-group, .bulk-status-group {
  display: flex;
  align-items: center;
  gap: 8px;
}

/* --- Input & Field Styling --- */

.compact-field {
  width: 150px;
}

.wide-field {
  width: 180px;
}

.bulk-status-field {
  width: 135px;
}

/* Override Mat-Field to look like a box */
::ng-deep .mat-mdc-form-field-flex {
  align-items: center !important;
  background-color: #fff !important;
}

