  --sidenav-item-icon-size: 24px;
  --sidenav-item-border-color: transparent;
  --sidenav-item-border-color-active: rgb(var(--color-primary));
  --sidenav-item-dropdown-background: #{color.adjust($sidenav-background, $lightness: -3%)};
