file.content:
/* Align nav block like left (Designflow) and right (icons): same padding rhythm */
.vex-toolbar-nav {
  /* Content-width (do not grow): items stay packed just after the logo and
     the trailing .flex-1 spacer absorbs all slack, pushing the right-side
     icons clear instead of crowding the last nav item. Shrink stays enabled
     so items can collapse on narrow screens. */
  flex: 0 1 auto;
  min-width: 0; /* allow shrinking below content size so right-side icons stay visible */
  /* PrimeNG menubar submenus are absolutely positioned below the nav row */
  overflow: visible;
  position: relative;
  display: flex;
  align-items: center;
  padding-left: 0;
  padding-right: var(--padding-gutter, 1rem);
  min-height: var(--toolbar-height);

