input.new_string:
/* Compact style when menubar is inside toolbar */
/* This layout sets --navigation-height: 0, which collapses the wrapper to
   zero height. Without flex-centering, the menubar (a block child) anchors at
   the wrapper's center line and flows DOWNWARD, spilling below the 64px toolbar
   as a phantom second row. Flex-centering seats it in the middle of the row. */
.vex-menubar-in-toolbar {
  display: flex;
  align-items: center;
}

:host .vex-menubar-in-toolbar ::ng-deep .vex-menubar {
  /* Tightened spacing so all top-level items + the right-side icons fit on a
     single row down to ~1280px viewports without overlapping. */
  .p-menubar-item-link,
  .p-menubar-item-content {
    padding: 0.3rem 0.4rem;
    border-radius: 6px;
  }

  .p-menubar-item-icon {
    margin-right: 0.3rem;
  }

  .p-menubar-root-list {
    gap: 0.15rem;
  }
}

