:host {
  background: var(--navigation-background);
  display: block;
  height: var(--navigation-height);
  position: relative;
  z-index: 200;
  overflow: visible;
}

.navigation {
  height: var(--navigation-height);
  overflow: visible;
}

.vex-menubar-wrapper {
  overflow: visible;
}

/* PrimeNG Menubar – smooth transitions and alignment with app theme */
:host ::ng-deep .vex-menubar {
  border: none;
  border-radius: 0;
  background: transparent;
  padding: 0;
  min-height: var(--navigation-height);
  display: flex;
  align-items: center;
  transition: background-color 0.2s ease, box-shadow 0.2s ease;

  .p-menubar-root-list {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    min-height: var(--navigation-height);
    flex-wrap: nowrap;
    overflow: visible;
  }

  .p-menuitem-icon,
  .p-menubar-item-icon {
    color: #ff4081; 
  }

  .p-menubar-button {
    display: none;

  }

  .p-menubar-item-link,
  .p-menubar-item-content {
    transition: background-color 0.2s ease, color 0.2s ease, transform 0.15s ease;
    border-radius: 6px;
    padding: 0.5rem 0.75rem;
    /* Default: transparent on dark header (no pink) */
  }

  /* Hover: subtle light overlay on dark header – neutral, not pink */
  .p-menubar-item:not(.p-disabled):hover .p-menubar-item-content,
  .p-menubar-item-link:hover,
  .p-menubar-item-content:hover {
    background: rgba(255, 255, 255, 0.12) !important;
  }

  .p-menubar-root-list > .p-menubar-item:not(.p-disabled):hover
  > .p-menubar-item-content
  .p-menubar-item-icon {
  color: #fff !important;
  }

  .p-menubar-item-link:focus-visible,
  .p-menubar-item-content:focus-visible {
    outline: 2px solid rgba(255, 255, 255, 0.6);
    outline-offset: 2px;
  }

  /* Submenu panel: above content and clearly visible (fixes invisible submenus) */
  .p-menubar-submenu,
  .p-submenu-list {
    z-index: 1100 !important;
    min-width: 8rem;
    width: max-content;
    max-width: 14rem;
    padding: 0.25rem 0;
    transition: opacity 0.2s ease, transform 0.15s ease;
    border-radius: 8px;
    box-shadow: 0 4px 20px rgba(0, 0, 0, 0.2);
    background: var(--background-base, #fff) !important;
    color: var(--text-color, #333) !important;
    border: 1px solid rgba(0, 0, 0, 0.08);
  }

  .p-menubar-submenu .p-menubar-item-link,
  .p-menubar-submenu .p-menuitem-link {
    color: inherit;
    padding: 0.4rem 0.75rem;
    min-width: 0;
  }

  /* Submenu hover: soft blue-grey instead of pink */
  .p-menubar-submenu .p-menubar-item-link:hover,
  .p-menubar-submenu .p-menuitem-link:hover {
    color: #fff !important;
  }

  .p-menuitem-link,
  .p-menubar-item-link {
    transition: background-color 0.2s ease, color 0.2s ease;
    border-radius: 4px;
  }

  .p-menuitem-link:hover,
  .p-menubar-item-link:hover {
    background: #d81b60  !important;
  }

  .p-menuitem-icon,
  .p-menubar-item-icon {
    margin-right: 0.5rem;
    transition: color 0.2s ease;
  }
}

/* Compact style when menubar is inside toolbar */
:host .vex-menubar-in-toolbar ::ng-deep .vex-menubar {
  .p-menubar-item-link,
  .p-menubar-item-content {
    padding: 0.35rem 0.6rem;
    border-radius: 6px;
  }
}

