25	    const overlayRef = this.overlay.create(this.getOverlayConfig({ origin, width, height, position, offsetX, offsetY }));
26	    const popoverRef = new PopoverRef<T>(overlayRef, content, data);
27	
28	    const injector = this.createInjector(popoverRef);
29	    overlayRef.attach(new ComponentPortal(PopoverComponent, null, injector));
30	
31	    return popoverRef;
32	  }
