34	  private createInjector(popoverRef: PopoverRef): Injector {
35	    return Injector.create({
36	      providers: [{ provide: PopoverRef, useValue: popoverRef }],
37	      parent: this.injector
38	    });
39	  }
40	
41	  private getOverlayConfig({ origin, width, height, position, offsetX, offsetY }): OverlayConfig {
42	    return new OverlayConfig({
43	      hasBackdrop: true,
44	      width,
45	      height,
46	      backdropClass: 'popover-backdrop',
47	      positionStrategy: this.getOverlayPosition({ origin, position, offsetX, offsetY }),
48	      scrollStrategy: this.overlay.scrollStrategies.reposition()
49	    });
50	  }
51	
52	  private getOverlayPosition({ origin, position, offsetX, offsetY }): PositionStrategy {
53	    return this.overlay.position()
54	      .flexibleConnectedTo(origin)
55	      .withPositions(position || this.getPositions())
56	      .withFlexibleDimensions(true)
57	      .withDefaultOffsetY(offsetY || 0)
58	      .withDefaultOffsetX(offsetX || 0)
59	      .withTransformOriginOn('.popover')
60	      .withPush(true);
61	  }
62	
63	  private getPositions(): ConnectionPositionPair[] {
64	    return [
65	      { originX: 'center', originY: 'top', overlayX: 'center', overlayY: 'bottom' },
66	      { originX: 'center', originY: 'bottom', overlayX: 'center', overlayY: 'top' }
67	    ];
68	  }
