import { Injectable } from '@angular/core';
import {
  PublicClientApplication,
  Configuration,
  AuthenticationResult,
  PopupRequest,
} from '@azure/msal-browser';
import { environment } from '../../../environments/environment';

/**
 * Thin wrapper around @azure/msal-browser for Azure AD SSO.
 *
 * We use the vanilla msal-browser package (not msal-angular) to avoid the
 * Angular-version coupling that the official msal-angular adapter brings.
 *
 * Lifecycle:
 *   1. Call `initialize()` once (done lazily on first `loginPopup()` call).
 *   2. Call `loginPopup()` to open the Microsoft login popup.
 *      Returns the raw Azure ID token string on success.
 */
@Injectable({ providedIn: 'root' })
export class AzureSsoService {
  private _msalInstance: PublicClientApplication | null = null;
  private _initPromise: Promise<void> | null = null;

  private get msalConfig(): Configuration {
    return {
      auth: {
        clientId: environment.azureClientId,
        authority: `https://login.microsoftonline.com/${environment.azureTenantId}`,
        redirectUri: window.location.origin + '/login',
      },
      cache: {
        cacheLocation: 'sessionStorage',
      },
    };
  }

  /** Lazily creates and initialises the MSAL instance (idempotent). */
  async initialize(): Promise<void> {
    if (this._initPromise) {
      return this._initPromise;
    }
    this._msalInstance = new PublicClientApplication(this.msalConfig);
    this._initPromise = this._msalInstance.initialize();
    return this._initPromise;
  }

  /**
   * Opens the Microsoft login popup and returns the Azure ID token string.
   * Throws on cancellation or error.
   */
  async loginPopup(): Promise<string> {
    await this.initialize();

    const request: PopupRequest = {
      scopes: ['openid', 'profile', 'email'],
      redirectUri: window.location.origin + '/assets/auth-redirect.html',
    };

    const result: AuthenticationResult = await this._msalInstance!.loginPopup(request);
    if (!result?.idToken) {
      throw new Error('No idToken in Microsoft authentication result');
    }
    return result.idToken;
  }

  /**
   * Signs the user out of the MSAL session (clears session storage cache).
   * Does NOT redirect — the caller should navigate to /login after this.
   */
  async logout(): Promise<void> {
    if (!this._msalInstance) return;
    await this._msalInstance.logoutPopup({ mainWindowRedirectUri: window.location.origin + '/login' });
  }
}

