// brevoService.js
const axios = require('axios');
const brevo = require('../config/brevo.config');

// Brevo client setup
const brevoClient = axios.create({
  baseURL: brevo.BASE_URL,
  headers: {
    accept: 'application/json',
    'api-key': brevo.API_KEY,
  },
});

function sendBrevoEmail(emails, template, subject, scheduledAt = null) {
  const sender = {
    email: brevo.SENDER_EMAIL,
    name: brevo.SENDER_NAME
  };

  const receivers = emails.map(email => ({ email }));

  const payload = {
    sender,
    to: receivers,
    subject,
    htmlContent: template,
    ...(scheduledAt && { scheduledAt }),
  };

  return brevoClient.post('/smtp/email', payload)
    .then(response => {
      return response.data.messageId;  // 🔥 Only return messageId
    })
    .catch(error => {
      if (error.response) {
        console.error("Brevo API Error:", error.response.status, error.response.data);
      } else {
        console.error("Unexpected Error:", error.message);
      }
      return null;
    });
}

exports.sendEmail = (emails, template, subject) => {
  return sendBrevoEmail(emails, template, subject);
};

exports.scheduledEmail = (emails, template, subject, scheduledAtTime) => {
  return sendBrevoEmail(emails, template, subject, scheduledAtTime);
};

