'use strict';
const path = require('path');
const { S3 } = require('@aws-sdk/client-s3');
const { getUserInfo } = require('../helpers/auth');
const UserService = require('../services/user.service');
const doConfig = require('../config/digitalocean.config');

const s3Client = new S3({
  forcePathStyle: false,
  endpoint: doConfig.ENDPOINT_URL,
  region: 'us-west-1',
  credentials: {
    accessKeyId: doConfig.ACCESS_KEY,
    secretAccessKey: doConfig.SECRET_KEY,
  },
});

/**
 * GET /api/user/me
 * Returns the authenticated user's profile: { firstName, name, email, photoUrl }
 */
const getProfile = async (req, res) => {
  const user = await getUserInfo(req.headers.authorization);
  if (!user) return res.status(403).json({ message: 'Invalid token' });
  try {
    const profile = await UserService.getProfile(user);
    if (!profile) return res.status(404).json({ message: 'User not found' });
    return res.json(profile);
  } catch (err) {
    return res.status(500).json({ message: 'Server error', error: err.message });
  }
};

/**
 * POST /api/user/photo
 * Accepts multipart/form-data field "photo".
 * Uploads to DO Spaces at key profile-photos/user-{userId}, stores URL in DB.
 * Returns { photoUrl }.
 */
const uploadProfilePhoto = async (req, res) => {
  const user = await getUserInfo(req.headers.authorization);
  if (!user) return res.status(403).json({ message: 'Invalid token' });
  if (!req.file) return res.status(400).json({ message: 'No file provided' });

  const ext = path.extname(req.file.originalname).toLowerCase() || '.jpg';
  // Vendor ids and users ids are independent sequences — prefix the key by role
  // so a vendor and a staff user with the same numeric id never collide in the bucket.
  const keyPrefix = user.role === 'vendor' ? 'vendor' : 'user';
  const key = `profile-photos/${keyPrefix}-${user.user_id}${ext}`;

  try {
    await s3Client.putObject({
      Bucket: doConfig.BUCKET_NAME,
      Key: key,
      Body: req.file.buffer,
      ContentType: req.file.mimetype,
      ACL: 'public-read',
    });
    const photoUrl = `${doConfig.PUBLIC_URL}/${key}`;
    await UserService.updateProfilePhoto(user, photoUrl);
    return res.json({ photoUrl });
  } catch (err) {
    return res.status(500).json({ message: 'Upload failed', error: err.message });
  }
};

module.exports = { getProfile, uploadProfilePhoto };

