'use strict';
const sql = require('../models/db');

const UserService = {};

/**
 * Return { firstName, name, email, photoUrl } for the authenticated user.
 * Accepts the decoded JWT ({ user_id, role }). Factory (vendor) users carry a
 * vendor_id in user_id and live in the `vendor` table, not `users`, so we must
 * branch on role — otherwise a vendor's id is looked up in `users`, misses, and
 * the endpoint 404s. Returns null if the user is not found.
 */
UserService.getProfile = async ({ user_id: userId, role }) => {
  if (role === 'vendor') {
    const vendor = await sql.vendor.findOne({
      where: { vendor_id: userId },
      attributes: ['vendor_id', 'vendor_name', 'vendor_lastname', 'vendor_email', 'vendor_profile_photo'],
    });
    if (!vendor) return null;
    return {
      firstName: vendor.vendor_name || '',
      name: `${vendor.vendor_name || ''} ${vendor.vendor_lastname || ''}`.trim(),
      email: vendor.vendor_email || '',
      photoUrl: vendor.vendor_profile_photo || null,
    };
  }
  const user = await sql.users.findOne({
    where: { id: userId },
    attributes: ['id', 'name', 'lastname', 'email', 'profile_photo'],
  });
  if (!user) return null;
  return {
    firstName: user.name || '',
    name: `${user.name || ''} ${user.lastname || ''}`.trim(),
    email: user.email || '',
    photoUrl: user.profile_photo || null,
  };
};

/**
 * Persist a new photo URL for the authenticated user. Returns the URL.
 * Branches on role so vendor avatars land in vendor.vendor_profile_photo
 * instead of writing to a non-existent users row.
 */
UserService.updateProfilePhoto = async ({ user_id: userId, role }, photoUrl) => {
  if (role === 'vendor') {
    await sql.vendor.update(
      { vendor_profile_photo: photoUrl },
      { where: { vendor_id: userId } }
    );
  } else {
    await sql.users.update(
      { profile_photo: photoUrl },
      { where: { id: userId } }
    );
  }
  return photoUrl;
};

module.exports = UserService;

var DBConfig = require('../config/db.config')()
var Sequelize = require('sequelize');
var db = {};

initialize();
async function initialize() {
    // connect to db
    let sq_config = {
        dialect: 'postgres',
        host: DBConfig.HOST,
        schema: process.env.SCHEMA,
        logging: false,
        pool: {
            max: 22,
            min: 1,
            acquire: 600000,
            idle: 100000,
        },
        createdAt: false,
        updatedAt: false,
        timestamp: false,
        dialectOptions: {
            connectTimeout: 3000000,
            // Force UTF-8 on the wire so multibyte text (e.g. Chinese headers)
            // can never be reinterpreted through a non-UTF-8 codepage. Defense
            // against the designflow_dev CP437 mojibake incident (see AGENTS.md).
            client_encoding: 'UTF8',
        }
    };

    const sequelize = new Sequelize(DBConfig.DB, DBConfig.DBUser, DBConfig.PASSWORD, sq_config);
    try {
        sequelize.authenticate();
        console.log('Connection has been established successfully.');
    } catch (error) {
        console.error('Unable to connect to the database:', error);
        throw 'Unable to connect to the database:', error
    }

    db =  require('./db/init-models')(sequelize);

    sequelize.sync();

    // Safe one-time migrations: ADD COLUMN IF NOT EXISTS never fails on re-deploy
    const schema = process.env.SCHEMA ? `"${process.env.SCHEMA}".` : '';
    sequelize.query(`ALTER TABLE ${schema}"RFQItem" ADD COLUMN IF NOT EXISTS "rfqItem_duty_rate_equation" VARCHAR(500)`)
      .catch(err => console.warn('Migration rfqItem_duty_rate_equation skipped:', err.message));
    sequelize.query(`ALTER TABLE ${schema}"customers" ADD COLUMN IF NOT EXISTS customers_logo VARCHAR(500)`)
      .catch(err => console.warn('Migration customers_logo skipped:', err.message));
    sequelize.query(`CREATE TABLE IF NOT EXISTS ${schema}app_settings (key VARCHAR(100) PRIMARY KEY, value TEXT, created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW())`)
      .catch(err => console.warn('Migration app_settings skipped:', err.message));
    // AI cache telemetry events — append-only per backend response. Admin AI Settings
    // aggregates this table to show whether prompt/context caching is actually paying off.
    sequelize.query(`CREATE TABLE IF NOT EXISTS ${schema}ai_cache_events (
      id UUID PRIMARY KEY,
      feature VARCHAR(80) NOT NULL DEFAULT 'unknown',
      provider VARCHAR(40) NOT NULL,
      api_backend VARCHAR(40) NOT NULL,
      model VARCHAR(160) NOT NULL,
      cache_strategy VARCHAR(40) NOT NULL,
      session_id VARCHAR(160),
      telemetry_available BOOLEAN NOT NULL DEFAULT false,
      prompt_tokens INTEGER NOT NULL DEFAULT 0,
      cache_hit_tokens INTEGER NOT NULL DEFAULT 0,
      cache_miss_tokens INTEGER NOT NULL DEFAULT 0,
      cache_creation_tokens INTEGER NOT NULL DEFAULT 0,
      completion_tokens INTEGER NOT NULL DEFAULT 0,
      reasoning_tokens INTEGER NOT NULL DEFAULT 0,
      total_tokens INTEGER NOT NULL DEFAULT 0,
      cache_hit_rate_pct DOUBLE PRECISION NOT NULL DEFAULT 0,
      created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
    )`).catch(err => console.warn('Migration ai_cache_events skipped:', err.message));
    sequelize.query(`CREATE INDEX IF NOT EXISTS ai_cache_events_created_at_idx ON ${schema}ai_cache_events (created_at DESC)`)
      .catch(err => console.warn('Migration ai_cache_events_created_at_idx skipped:', err.message));
    sequelize.query(`CREATE INDEX IF NOT EXISTS ai_cache_events_feature_created_at_idx ON ${schema}ai_cache_events (feature, created_at DESC)`)
      .catch(err => console.warn('Migration ai_cache_events_feature_created_at_idx skipped:', err.message));
    sequelize.query(`ALTER TABLE ${schema}"users" ADD COLUMN IF NOT EXISTS profile_photo TEXT`)
      .catch(err => console.warn('Migration users.profile_photo skipped:', err.message));
    // vendor.vendor_profile_photo — factory (vendor) users live in the vendor table,
    // not users, so /api/user/me and /api/user/photo read/store their avatar here.
    sequelize.query(`ALTER TABLE ${schema}"vendor" ADD COLUMN IF NOT EXISTS vendor_profile_photo TEXT`)
      .catch(err => console.warn('Migration vendor.vendor_profile_photo skipped:', err.message));
    // RFQItem.price_sales_snapshots — per-row JSON map of price_sales colId ->
    // {duty_rate, duty_dollar, container_price, at}, snapshotting the cost inputs at
    // the moment each "Price for Sales" cell was last populated (shown as a cell tooltip).
    sequelize.query(`ALTER TABLE ${schema}"RFQItem" ADD COLUMN IF NOT EXISTS "rfqItem_price_sales_snapshots" TEXT`)
      .catch(err => console.warn('Migration rfqItem_price_sales_snapshots skipped:', err.message));
    // RFQItem.factories_step_at — timestamp for when an item moves to @factories.
    // The mixed-case identifier must be quoted to match Sequelize's generated SQL.
    sequelize.query(`ALTER TABLE ${schema}"RFQItem" ADD COLUMN IF NOT EXISTS "rfqItem_factories_step_at" TIMESTAMPTZ`)
      .catch(err => console.warn('Migration rfqItem_factories_step_at skipped:', err.message));
    // Clean up the empty lowercase orphan column an earlier UNQUOTED version of the
    // migration above accidentally created (Postgres folds unquoted identifiers to
    // lowercase). It is distinct from the correct mixed-case column and unused.
    // Quoted-lowercase DROP targets only the orphan; safe + idempotent via IF EXISTS.
    sequelize.query(`ALTER TABLE ${schema}"RFQItem" DROP COLUMN IF EXISTS "rfqitem_price_sales_snapshots"`)
      .catch(err => console.warn('Migration drop orphan rfqitem_price_sales_snapshots skipped:', err.message));
    // RFQVendor.requote_requested — true when Sourcing has asked the factory to
    // refresh a stale quote. Drives the orange highlight + "Quoted <date>" tooltip
    // in the RFQ detail grid; cleared when the vendor re-quotes or clicks "Keep Price".
    sequelize.query(`ALTER TABLE ${schema}"RFQVendor" ADD COLUMN IF NOT EXISTS "requote_requested" BOOLEAN DEFAULT false`)
      .catch(err => console.warn('Migration RFQVendor.requote_requested skipped:', err.message));
    // RFQVendor.RFQVendor_archived — PER-VENDOR archive flag. Set by the lazy sweep
    // in Customer.getAll (helpers/archive-stale-quotes.js) for a factory's own quote
    // rows that were priced and whose quote_date is >3 months old. Drives the vendor's
    // archive/active tab split independently of the global RFQItem.rfqItem_archive flag,
    // so one vendor archiving a stale quote never hides the item from Sourcing or other
    // factories. Mixed-case identifier MUST be quoted (see §11 / SYS-002).
    sequelize.query(`ALTER TABLE ${schema}"RFQVendor" ADD COLUMN IF NOT EXISTS "RFQVendor_archived" BOOLEAN DEFAULT false`)
      .catch(err => console.warn('Migration RFQVendor.RFQVendor_archived skipped:', err.message));
    // RFQVendor.RFQVendor_archive_optout — sticky "vendor manually un-archived this"
    // marker. The lazy sweep skips opted-out rows so a manual un-archive is not undone
    // on the next list load. Cleared whenever the quote cycle resets (fresh price,
    // keepPrice, or a re-quote request), so the 3-month auto-archive can apply again.
    // Mixed-case identifier MUST be quoted (see §11 / SYS-002).
    sequelize.query(`ALTER TABLE ${schema}"RFQVendor" ADD COLUMN IF NOT EXISTS "RFQVendor_archive_optout" BOOLEAN DEFAULT false`)
      .catch(err => console.warn('Migration RFQVendor.RFQVendor_archive_optout skipped:', err.message));
    // Factory.factory_country — country where the factory operates (FOB origin).
    // Used to auto-fill FOB Country on quote rows and to match the Trump 2025
    // reciprocal tariff rate when calculating duty.
    sequelize.query(`ALTER TABLE ${schema}"Factory" ADD COLUMN IF NOT EXISTS factory_country VARCHAR(255)`)
      .catch(err => console.warn('Migration Factory.factory_country skipped:', err.message));
    // One-time backfill: set factory_country from the most common vendor_country
    // among vendors linked to each factory. Only fills NULLs so it is safe to re-run.
    sequelize.query(`
      UPDATE ${schema}"Factory" f
      SET factory_country = sub.country
      FROM (
        SELECT factory_id_fk, vendor_country AS country,
               ROW_NUMBER() OVER (PARTITION BY factory_id_fk ORDER BY COUNT(*) DESC) AS rn
        FROM ${schema}vendor
        WHERE factory_id_fk IS NOT NULL AND vendor_country IS NOT NULL AND vendor_country <> ''
        GROUP BY factory_id_fk, vendor_country
      ) sub
      WHERE sub.rn = 1 AND sub.factory_id_fk = f.id
        AND (f.factory_country IS NULL OR f.factory_country = '')
    `).catch(err => console.warn('Backfill Factory.factory_country skipped:', err.message));
    // grid_cell_notes — per-cell AG Grid notes keyed by grid_type + row_id + col_id.
    // Reusable across RFQ, Item Library, and License Tracking grids.
    sequelize.query(`CREATE TABLE IF NOT EXISTS ${schema}grid_cell_notes (
      id UUID PRIMARY KEY,
      grid_type VARCHAR(50) NOT NULL,
      row_id VARCHAR(255) NOT NULL,
      col_id VARCHAR(255) NOT NULL,
      note_text TEXT,
      note_author VARCHAR(255),
      note_read_only BOOLEAN NOT NULL DEFAULT false,
      created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
      updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
    )`).catch(err => console.warn('Migration grid_cell_notes skipped:', err.message));
    sequelize.query(`CREATE UNIQUE INDEX IF NOT EXISTS grid_cell_notes_grid_row_col_uq ON ${schema}grid_cell_notes (grid_type, row_id, col_id)`)
      .catch(err => console.warn('Migration grid_cell_notes_grid_row_col_uq skipped:', err.message));
    sequelize.query(`CREATE INDEX IF NOT EXISTS grid_cell_notes_grid_type_idx ON ${schema}grid_cell_notes (grid_type)`)
      .catch(err => console.warn('Migration grid_cell_notes_grid_type_idx skipped:', err.message));
}
module.exports = db;

