'use strict';

/**
 * Microsoft Graph (app-only / client-credentials) configuration.
 *
 * Reuses the same Azure App Registration as SSO (AZURE_CLIENT_ID / AZURE_TENANT_ID)
 * plus a client secret that must be provisioned separately (Secret Manager —
 * never committed). The Graph app permission `User.Read.All` (application) must be
 * granted admin consent for photo reads of other users to work.
 *
 * Getters read process.env on access so tests can toggle configuration, and so a
 * missing secret simply makes `isConfigured` false (callers no-op gracefully —
 * the app falls back to uploaded photos / initials and never errors).
 */
module.exports = {
  get CLIENT_ID() { return process.env.AZURE_CLIENT_ID; },
  get TENANT_ID() { return process.env.AZURE_TENANT_ID; },
  get CLIENT_SECRET() { return process.env.AZURE_CLIENT_SECRET; },
  get isConfigured() {
    return Boolean(
      process.env.AZURE_CLIENT_ID &&
      process.env.AZURE_TENANT_ID &&
      process.env.AZURE_CLIENT_SECRET
    );
  },
};

