input.content:
'use strict';

// Syncs staff users' Microsoft 365 / Teams profile photos into DO Spaces and
// persists the public URL on users.graph_photo. Uploaded photos always win over
// Graph photos (see effectivePhoto). Vendors are external (not in the M365
// tenant) so they are never synced here.
const { S3 } = require('@aws-sdk/client-s3');
const sql = require('../models/db');
const doConfig = require('../config/digitalocean.config');
const graphConfig = require('../config/graph.config');
const { fetchUserPhoto } = require('../helpers/graph');

const s3Client = new S3({
  forcePathStyle: false,
  endpoint: doConfig.ENDPOINT_URL,
  region: 'us-west-1',
  credentials: {
    accessKeyId: doConfig.ACCESS_KEY,
    secretAccessKey: doConfig.SECRET_KEY,
  },
});

// Re-check a user's M365 photo at most this often. The synced_at stamp is written
// even when the user has no photo, so we don't hammer Graph for photoless users.
const SYNC_TTL_MS = 7 * 24 * 60 * 60 * 1000; // 7 days

function isFresh(syncedAt) {
  if (!syncedAt) return false;
  return Date.now() - new Date(syncedAt).getTime() < SYNC_TTL_MS;
}

/** Effective avatar URL for a user row: uploaded photo wins, then Graph, then none. */
function effectivePhoto(user) {
  if (!user) return null;
  return user.profile_photo || user.graph_photo || null;
}

function extFor(contentType) {
  return contentType && contentType.includes('png') ? '.png' : '.jpg';
}

/**
 * Best-effort: fetch one staff user's M365 photo, cache it in DO Spaces, and
 * persist users.graph_photo + graph_photo_synced_at. Throttled by SYNC_TTL_MS.
 * Never throws. Returns the (possibly unchanged) graph_photo URL or null.
 *
 * @param {{id:number, email:string, profile_photo?:string, graph_photo?:string, graph_photo_synced_at?:Date}} user
 */
async function syncStaffPhoto(user) {
  if (!user || !graphConfig.isConfigured) return user ? user.graph_photo || null : null;
  const { id, email, graph_photo, graph_photo_synced_at } = user;
  if (!id || !email) return graph_photo || null;
  if (isFresh(graph_photo_synced_at)) return graph_photo || null;

  const syncedAt = new Date();

  let photo = null;
  try {
    photo = await fetchUserPhoto(email);
  } catch {
    photo = null;
  }

  if (!photo) {
    // Stamp the attempt so photoless users aren't re-fetched on every request.
    try {
      await sql.users.update({ graph_photo_synced_at: syncedAt }, { where: { id } });
    } catch { /* best-effort */ }
    return graph_photo || null;
  }

  const key = `profile-photos/graph-user-${id}${extFor(photo.contentType)}`;
  try {
    await s3Client.putObject({
      Bucket: doConfig.BUCKET_NAME,
      Key: key,
      Body: photo.buffer,
      ContentType: photo.contentType,
      ACL: 'public-read',
    });
    // Cache-bust so a refreshed M365 photo replaces the browser-cached copy.
    const url = `${doConfig.PUBLIC_URL}/${key}?v=${syncedAt.getTime()}`;
    await sql.users.update(
      { graph_photo: url, graph_photo_synced_at: syncedAt },
      { where: { id } }
    );
    return url;
  } catch (err) {
    console.warn(`graph-photo: caching failed for user ${id}:`, err.message);
    return graph_photo || null;
  }
}

/**
 * Background backfill for a list of user rows: sync up to `max` staff users that
 * have no uploaded photo and are stale. Bounded so it never floods Graph; over
 * repeated calls (e.g. each mention-autocomplete load) the whole org fills in.
 * Fire-and-forget from callers (returns a promise but is safe to ignore).
 */
async function backfillStale(users, max = 10) {
  if (!graphConfig.isConfigured || !Array.isArray(users)) return;
  const stale = users
    .filter((u) => u && u.email && !u.profile_photo && !isFresh(u.graph_photo_synced_at))
    .slice(0, max);
  await Promise.all(stale.map((u) => syncStaffPhoto(u).catch(() => {})));
}

module.exports = { syncStaffPhoto, backfillStale, effectivePhoto, isFresh, SYNC_TTL_MS };

