};

// Returns all active users (id, name, lastname, email, profile_photo) for @mention autocomplete.
// profile_photo is the EFFECTIVE avatar: an uploaded photo if present, else the
// cached M365/Teams (Graph) photo — so the frontend needs no change. A bounded
// background backfill tops up stale users without blocking the response.
NotificationService.getMentionableUsers = async () => {
  const users = await sql.users.findAll({
    where: { status: 'active' },
    attributes: ['id', 'name', 'lastname', 'email', 'profile_photo', 'graph_photo', 'graph_photo_synced_at'],
    order: [['name', 'ASC']],
  });
  // Fire-and-forget: sync a few stale users' Graph photos for next time.
  GraphPhotoService.backfillStale(users).catch(() => {});
  return users.map((u) => ({
    id: u.id,
    name: u.name,
    lastname: u.lastname,
    email: u.email,
    profile_photo: GraphPhotoService.effectivePhoto(u),
  }));
};

module.exports = NotificationService;

