'use strict';
/**
 * Regression tests for the db.js startup migrations.
 *
 * These tests guard against a class of bug where a Sequelize model column is
 * added without a corresponding ALTER TABLE migration.  When that happens,
 * every sql.<model>.findOne() without explicit `attributes` fails because
 * Sequelize generates a SELECT that references the missing column, and
 * PostgreSQL returns "column does not exist".
 *
 * Bug history: profile_photo was added to the users Sequelize model (commit
 * 53cc531) but no ALTER TABLE was included.  Every login attempt (and any
 * other sql.users.findOne() call) failed, producing SYS-030 errors and
 * unhandled-rejection crashes (503 on Cloud Run).
 */

const { readFileSync } = require('fs');
const { join } = require('path');

const DB_JS_PATH        = join(__dirname, '../../models/db.js');
const USERS_MODEL_PATH  = join(__dirname, '../../models/db/users.js');
const RFQITEM_MODEL_PATH = join(__dirname, '../../models/db/RFQItem.js');
const RFQVENDOR_MODEL_PATH = join(__dirname, '../../models/db/RFQVendor.js');
const VENDOR_MODEL_PATH = join(__dirname, '../../models/db/vendor.js');
const AI_CACHE_EVENT_MODEL_PATH = join(__dirname, '../../models/db/AiCacheEvent.js');

const dbSource        = readFileSync(DB_JS_PATH,         'utf8');
const usersSource     = readFileSync(USERS_MODEL_PATH,   'utf8');
const rfqItemSource   = readFileSync(RFQITEM_MODEL_PATH, 'utf8');
const rfqVendorSource = readFileSync(RFQVENDOR_MODEL_PATH, 'utf8');
const vendorSource    = readFileSync(VENDOR_MODEL_PATH,  'utf8');
const aiCacheEventSource = readFileSync(AI_CACHE_EVENT_MODEL_PATH, 'utf8');

// ─── models/db/users.js ───────────────────────────────────────────────────────

describe('users Sequelize model', () => {
  it('defines profile_photo so Sequelize includes it in generated SELECT queries', () => {
    expect(usersSource).toContain('profile_photo');
  });

  it('defines profile_photo as TEXT type', () => {
    expect(usersSource).toMatch(/profile_photo[\s\S]{0,60}DataTypes\.TEXT/);
  });
});

// ─── models/db.js migrations ─────────────────────────────────────────────────

describe('db.js startup migrations', () => {
  it('contains the profile_photo ALTER TABLE migration', () => {
    // The migration must use ADD COLUMN IF NOT EXISTS so it is safe to re-run.
    expect(dbSource).toMatch(
      /ALTER TABLE.*"users".*ADD COLUMN IF NOT EXISTS\s+profile_photo\s+TEXT/,
    );
  });

  it('profile_photo migration uses IF NOT EXISTS so re-deploys are safe', () => {
    expect(dbSource).toContain('ADD COLUMN IF NOT EXISTS profile_photo TEXT');
  });

  it('existing migrations are still present (rfqItem_duty_rate_equation)', () => {
    expect(dbSource).toContain('rfqItem_duty_rate_equation');
  });

