'use strict';
/**
 * Unit tests for the Microsoft Graph profile-photo integration.
 * Network (axios), storage (S3), and DB (models/db) are mocked, so these verify
 * the pure logic: configuration gating, upload precedence, sync throttling.
 */

jest.mock('@aws-sdk/client-s3', () => ({
  S3: jest.fn().mockImplementation(() => ({ putObject: jest.fn().mockResolvedValue({}) })),
}));
jest.mock('../../models/db', () => ({
  users: { update: jest.fn().mockResolvedValue([1]) },
}));
jest.mock('../../helpers/graph', () => ({
  fetchUserPhoto: jest.fn(),
}));

const sql = require('../../models/db');
const { fetchUserPhoto } = require('../../helpers/graph');
const GraphPhoto = require('../../services/graph-photo.service');

const ORIGINAL_ENV = { ...process.env };

function configureGraph() {
  process.env.AZURE_CLIENT_ID = 'client-id';
  process.env.AZURE_TENANT_ID = 'tenant-id';
  process.env.AZURE_CLIENT_SECRET = 'secret';
}
function unconfigureGraph() {
  delete process.env.AZURE_CLIENT_SECRET;
}

beforeEach(() => {
  jest.clearAllMocks();
  process.env = { ...ORIGINAL_ENV };
});
afterAll(() => { process.env = ORIGINAL_ENV; });

describe('effectivePhoto', () => {
  it('prefers an uploaded photo over a Graph photo', () => {
    expect(GraphPhoto.effectivePhoto({ profile_photo: 'up.jpg', graph_photo: 'g.jpg' })).toBe('up.jpg');
  });
  it('falls back to the Graph photo when there is no upload', () => {
    expect(GraphPhoto.effectivePhoto({ profile_photo: null, graph_photo: 'g.jpg' })).toBe('g.jpg');
  });
  it('returns null when neither is set', () => {
    expect(GraphPhoto.effectivePhoto({})).toBeNull();
    expect(GraphPhoto.effectivePhoto(null)).toBeNull();
  });
});

describe('isFresh', () => {
  it('is false with no timestamp', () => {
    expect(GraphPhoto.isFresh(null)).toBe(false);
  });
  it('is true within the TTL', () => {
    expect(GraphPhoto.isFresh(new Date())).toBe(true);
  });
  it('is false past the TTL', () => {
    expect(GraphPhoto.isFresh(new Date(Date.now() - GraphPhoto.SYNC_TTL_MS - 1000))).toBe(false);
  });
});

describe('syncStaffPhoto', () => {
  it('no-ops (no Graph call) when Graph is not configured', async () => {
    unconfigureGraph();
    const res = await GraphPhoto.syncStaffPhoto({ id: 1, email: 'a@x.com', graph_photo: 'old.jpg' });
    expect(res).toBe('old.jpg');
    expect(fetchUserPhoto).not.toHaveBeenCalled();
  });

  it('skips the Graph call when the last sync is still fresh', async () => {
    configureGraph();
    const res = await GraphPhoto.syncStaffPhoto({
      id: 1, email: 'a@x.com', graph_photo: 'cached.jpg', graph_photo_synced_at: new Date(),
    });
    expect(res).toBe('cached.jpg');
    expect(fetchUserPhoto).not.toHaveBeenCalled();
  });

  it('uploads and persists the URL when a stale user has a Graph photo', async () => {
    configureGraph();
    fetchUserPhoto.mockResolvedValue({ buffer: Buffer.from('img'), contentType: 'image/jpeg' });
    const res = await GraphPhoto.syncStaffPhoto({ id: 42, email: 'a@x.com', graph_photo: null, graph_photo_synced_at: null });
    expect(fetchUserPhoto).toHaveBeenCalledWith('a@x.com');
    expect(res).toContain('profile-photos/graph-user-42.jpg');
    expect(sql.users.update).toHaveBeenCalledWith(
      expect.objectContaining({ graph_photo: expect.stringContaining('graph-user-42.jpg') }),
      { where: { id: 42 } },
    );
  });

  it('only stamps synced_at (no URL) when the user has no Graph photo', async () => {
    configureGraph();
    fetchUserPhoto.mockResolvedValue(null);
    const res = await GraphPhoto.syncStaffPhoto({ id: 7, email: 'a@x.com', graph_photo: null, graph_photo_synced_at: null });
    expect(res).toBeNull();
    expect(sql.users.update).toHaveBeenCalledWith(
      expect.not.objectContaining({ graph_photo: expect.anything() }),
      { where: { id: 7 } },
    );
  });
});

describe('backfillStale', () => {
  it('only syncs users without an upload and past the TTL, bounded by max', async () => {
    configureGraph();
    fetchUserPhoto.mockResolvedValue(null);
    const users = [
      { id: 1, email: 'a@x.com', profile_photo: 'up.jpg', graph_photo_synced_at: null }, // has upload -> skip
      { id: 2, email: 'b@x.com', profile_photo: null, graph_photo_synced_at: new Date() }, // fresh -> skip
      { id: 3, email: 'c@x.com', profile_photo: null, graph_photo_synced_at: null },        // stale -> sync
      { id: 4, email: null, profile_photo: null, graph_photo_synced_at: null },             // no email -> skip
    ];
    await GraphPhoto.backfillStale(users, 10);
    expect(fetchUserPhoto).toHaveBeenCalledTimes(1);
    expect(fetchUserPhoto).toHaveBeenCalledWith('c@x.com');
  });
});

