Customer.getAllUsers = async (req, result) => {
  if (req.body.userType && req.body.userType.title === 'Factories & Reps') {
    try {
      const commonStatusCondition = { [Op.or]: req.body.userStatus };

      const factoriesPromise = sql.Factory.findAll({ where: { factory_status: commonStatusCondition } });
      const vendorsPromise = sql.vendor.findAll({ where: { vendor_status: commonStatusCondition, vendor_access: req.body.signUpStatus.value } });
      const factoryHeadersPromise = sql.GridLayout.findAll({ where: { layout_name: 'Default', grid_id: 'manage_factories', user_id_fk: null }, order: [['col_order', 'ASC']], raw: true });
      const vendorHeadersPromise = sql.GridLayout.findAll({ where: { layout_name: 'Default', grid_id: 'manage_vendors', user_id_fk: null }, order: [['col_order', 'ASC']], raw: true });

      const [factories, vendors, factoryHeaders, vendorHeaders] = await Promise.all([factoriesPromise, vendorsPromise, factoryHeadersPromise, vendorHeadersPromise]);

      const vendorsByFactoryId = vendors.reduce((acc, v) => {
        const vendor = v.get({ plain: true });
        const factoryId = vendor.factory_id_fk;
        if (factoryId) {
          if (!acc[factoryId]) acc[factoryId] = [];
          acc[factoryId].push(vendor);
        }
        return acc;
      }, {});

      const resultData = factories.map(f => {
        const plainFactory = f.get({ plain: true });
        let masterRow = { id: plainFactory.id };
        for (const header of factoryHeaders) {
          masterRow[header.field] = plainFactory[header.col_id];
        }
        // Explicitly map the status field and provide a default
        const statusHeader = factoryHeaders.find(h => h.col_id === 'status');
        if (statusHeader) {
          masterRow[statusHeader.field] = plainFactory.factory_status || 'Active';
        }
        // Always include factory_country regardless of GridLayout configuration
        masterRow.factory_country = plainFactory.factory_country ?? null;

        const detailVendors = vendorsByFactoryId[plainFactory.id] || [];
        masterRow.Vendors = detailVendors.map(vendor => {
          let detailRow = { vendor_id: vendor.vendor_id };
          for (const header of vendorHeaders) {
            const valueMap = {
              'id': vendor.vendor_id, 'first_name': vendor.vendor_name, 'last_name': vendor.vendor_lastname, 'email': vendor.vendor_email, 'phone': vendor.vendor_phone1, 'status': vendor.vendor_status, 'wechat_id': vendor.vendor_wechatId, 'company_name': vendor.vendor_company_name, 'company_nickname': vendor.vendor_company_nickname, 'address': vendor.vendor_address1,
            };
            detailRow[header.field] = valueMap[header.col_id] || vendor[header.col_id] || null;
          }
          return detailRow;
        });
        return masterRow;
      });

      return result(null, resultData);

    } catch (err) {
      return result(err, null);
    }
  }
  let tableName = 'users'
  if (req.body.signUpStatus.value == 'temporary') {
    req.body.userStatus = ['', null]
  }
  let condition = {
    status: {
      [Op.or]: req.body.userStatus
    },
  }
  if (req.body.userType.title == 'Vendor') {
    tableName = 'vendor';
    condition = {
      vendor_status: {
        [Op.or]: req.body.userStatus
      },
      vendor_access: req.body.signUpStatus.value
    }
  }
  if (req.body.userType.title == 'Factory') {
    tableName = 'Factory';
    condition = {
      factory_status : {
        [Op.or]: req.body.userStatus
      }
    }
  }

  await sql[tableName].findAll({
    where: condition,
    ...(tableName === 'users' && { order: [['id', 'ASC']] })
  }).then(async (data) => {
    let mapData = []
    if (data) {
      if (req.body.userType.title == 'Vendor') {
        let colHeaders = await getGridHeader(req.body.userType.value)
        mapData = await utility.mapVendor(colHeaders, data)
      } else if(req.body.userType.title === 'Factory'){
        let colHeaders = await getGridHeader(req.body.userType.value)
        mapData = await utility.mapFactory(colHeaders, data)
      } else {
        let colHeaders = await getGridHeader(req.body.userType.value)
        mapData = await utility.mapUser(colHeaders, data)
      }
    }
    result(null, mapData);
  }).catch(err => {
    result(err, null);
  });
}

