var Sequelize = require('sequelize');
var { Op } = require('sequelize');
const GraphPhotoService = require('./graph-photo.service');

const CommentService = function () {};

CommentService.getComments = async (item_header_id) => {
  const rows = await sql.comments.findAll({
    order: [Sequelize.literal('id DESC'), Sequelize.literal('inserted_date DESC')],
    where: {
      item_header_id
    },
    as: 'comments',
    include: [{
      model: sql.users,
      as: 'users',
      // photo columns added so each comment can carry the author's effective avatar
      attributes: ['id', 'name', 'email', 'profile_photo', 'graph_photo', 'graph_photo_synced_at'],
    }, {
