var Sequelize = require('sequelize');
var { Op } = require('sequelize');

const CommentService = function () {};

CommentService.getComments = async (item_header_id) => {
  return sql.comments.findAll({
    order: [Sequelize.literal('id DESC'), Sequelize.literal('inserted_date DESC')],
    where: {
      item_header_id
    },
    as: 'comments',
    include: [{
      model: sql.users,
      as: 'users',
      attributes: ['id', 'name', 'email'],
    }, {
      model: sql.itemAttachment,
      as: 'itemAttachments',
      attributes: ['item_attachment_id', 'attachment_link', 'item_attachment_fileName'],
    }]
  })
}

CommentService.addComment = async (commentObj) => {
  const { comment, item_header_id, user_id, parent_id } = commentObj
  const inserted_date = new Date()
  return await sql.comments.create({
    comment,
    inserted_date,
    item_header_id,
    user_id,
    parent_id
  })
}

CommentService.updateComment = async (id, body) => {
  const inserted_date = new Date()
  const comment = body.comment
  const instance = await sql.comments.findByPk(id);
  if (instance) {
    return await instance.update({ comment, inserted_date });
  }
  return null;
}

CommentService.deleteComment = async (id) => {
  return await sql.comments.destroy({ where: { id } })
}

module.exports = CommentService

