/**
 * Wiring tests: the comment author avatar (author_photo) and the admin user
 * grid 'pic' column both derive from GraphPhotoService.effectivePhoto
 * (uploaded photo wins, else cached M365/Graph photo).
 */

jest.mock('../../models/db', () => ({
  comments: { findAll: jest.fn() },
  users: {},
  itemAttachment: {},
}));
jest.mock('../../helpers/rfqListQuery', () => ({
  buildMerchGroupMap: jest.fn(),
  resolveMerchGroupValue: jest.fn(),
}));
jest.mock('../../services/graph-photo.service', () => ({
  effectivePhoto: (u) => (u ? (u.profile_photo || u.graph_photo || null) : null),
  backfillStale: jest.fn().mockResolvedValue(undefined),
  syncStaffPhoto: jest.fn(),
}));

const sql = require('../../models/db');
const GraphPhoto = require('../../services/graph-photo.service');
const CommentService = require('../../services/comment.service');
const utility = require('../../helpers/utility');

beforeEach(() => jest.clearAllMocks());

describe('CommentService.getComments', () => {
  it('attaches the effective author_photo and triggers a background backfill', async () => {
    const author = { id: 5, profile_photo: null, graph_photo: 'g.jpg' };
    sql.comments.findAll.mockResolvedValue([
      { users: [author], toJSON: () => ({ id: 1, comment: 'hi', users: [author] }) },
    ]);
    const res = await CommentService.getComments(99);
    expect(res[0].author_photo).toBe('g.jpg');
    expect(GraphPhoto.backfillStale).toHaveBeenCalled();
  });

  it('author_photo is null when a comment has no author', async () => {
    sql.comments.findAll.mockResolvedValue([
      { users: [], toJSON: () => ({ id: 2, comment: 'x', users: [] }) },
    ]);
    const res = await CommentService.getComments(99);
    expect(res[0].author_photo).toBeNull();
  });
});

